// Get the raw text from the webhook body
const rawText = $input.first().json.body.rawText || '';

// Remove HTML tags
let cleanedText = rawText.replace(/<[^>]*>/g, '');

// Decode HTML entities
cleanedText = cleanedText
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

// Normalize whitespace (replace tabs and multiple spaces with a single space)
cleanedText = cleanedText.replace(/[\t ]+/g, ' ');

// Collapse multiple line breaks into max 2
cleanedText = cleanedText.replace(/\n{3,}/g, '\n\n');

// Trim each line
cleanedText = cleanedText.split('\n').map(line => line.trim()).join('\n');

// Trim overall
cleanedText = cleanedText.trim();

// Return the cleaned text
return [{
  json: {
    raw_text: cleanedText
  }
}];

