// ---------------------------------------------
// Map structured document → DOCX style mapping
// FIX: Strip markdown code fences before JSON.parse()
// ---------------------------------------------

// Word style mapping for block types
const blockStyleMap = {
  "paragraph": "GBM Normal1",
  "bullet_list": "GBM Dash Bullet",
  "note": "GBM Note",
  "raw": "GBM Raw"
};

// Heading level → Word style
const headingStyleMap = {
  1: "Heading 1",
  2: "Heading 2",
  3: "Heading 3"
};

// Load structured document (the LLM returned JSON as a string)
const raw = $input.first().json;
let rawStr = raw.text || raw.output?.[0]?.content?.[0]?.text || '';

// Strip markdown code fences that LLMs sometimes add (```json ... ``` or ``` ... ```)
rawStr = rawStr.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

let doc;
try {
  doc = JSON.parse(rawStr);
} catch (e) {
  throw new Error('Structure Document returned invalid JSON. Raw output: ' + rawStr.slice(0, 300));
}

// Transform sections + blocks into a flat render list
const styled = [];

doc.sections.forEach(section => {
  // Push the heading itself as a block
  styled.push({
    type: "heading",
    text: section.heading,
    level: section.level,
    word_style: headingStyleMap[section.level] || "Heading 1"
  });

  // Process all content blocks within the section
  section.content_blocks.forEach(block => {
    styled.push({
      type: block.type,
      text: block.text,
      word_style: blockStyleMap[block.type] || "GBM Normal1"
    });
  });
});

// Output formatted blocks + metadata
return [{
  json: {
    title: doc.title,
    document_type: doc.document_type,
    styled_blocks: styled
  }
}];

